import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import axios from 'axios';

const Register = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    grade: '',
    division: '',
    project_title: '',
    abstract: '',
    parent_name: '',
    parent_phone: '',
    parent_email: ''
  });

  const [registrationData, setRegistrationData] = useState(null);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    const phoneRegex = /^[6-9]\d{9}$/;
    if (!phoneRegex.test(formData.parent_phone)) {
      toast.error('Please enter a valid 10-digit Indian mobile number');
      setLoading(false);
      return;
    }

    try {
      const response = await axios.post(
        'http://localhost:5000/api/auth/register',
        formData
      );

      if (response.data.success) {
        setRegistrationData(response.data.data);
        toast.success('✅ Registration successful! WhatsApp message sent to parent');
      }
    } catch (error) {
      toast.error(error.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  if (registrationData) {
    return (
      <div className="max-w-md mx-auto mt-10 p-6 bg-white rounded-lg shadow-lg">
        <div className="text-center">
          <div className="text-6xl mb-4">🎉</div>
          <h2 className="text-2xl font-bold text-green-600 mb-4">
            Registration Successful!
          </h2>
          <p className="text-sm text-gray-600 mb-2">
            WhatsApp sent to <strong>{registrationData.parent_phone}</strong>
          </p>
          
          <div className="bg-gray-50 p-4 rounded-lg mb-4">
            <p className="text-sm"><strong>Group Code:</strong></p>
            <p className="text-xl font-mono font-bold text-blue-600">
              {registrationData.registration_code}
            </p>
            <p className="text-sm mt-2"><strong>Password:</strong></p>
            <p className="text-xl font-mono font-bold text-red-600">
              {registrationData.password}
            </p>
          </div>

          {registrationData.qr_code && (
            <div className="mb-4">
              <p className="text-sm text-gray-600 mb-2">Your QR Code:</p>
              <img 
                src={registrationData.qr_code} 
                alt="QR Code" 
                className="mx-auto w-32 h-32 border-2 border-gray-200 rounded-lg"
              />
            </div>
          )}

          <button
            onClick={() => navigate('/dashboard')}
            className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700"
          >
            Go to Dashboard
          </button>

          <p className="mt-4 text-xs text-red-500">
            ⚠️ Save these credentials immediately! You won't see them again.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto mt-10 p-6 bg-white rounded-lg shadow-lg">
      <h2 className="text-2xl font-bold text-center mb-6">
        🏫 Science Fair Registration
      </h2>
      
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700">Grade</label>
            <select
              name="grade"
              value={formData.grade}
              onChange={handleChange}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500"
              required
            >
              <option value="">Select</option>
              {[4,5,6,7,8,9,10].map(g => (
                <option key={g} value={g}>Grade {g}</option>
              ))}
            </select>
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700">Division</label>
            <select
              name="division"
              value={formData.division}
              onChange={handleChange}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500"
              required
            >
              <option value="">Select</option>
              {['A','B','C','D','E','F','G','H','I'].map(d => (
                <option key={d} value={d}>Division {d}</option>
              ))}
            </select>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700">Project Title</label>
          <input
            type="text"
            name="project_title"
            value={formData.project_title}
            onChange={handleChange}
            className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700">Abstract</label>
          <textarea
            name="abstract"
            rows="3"
            value={formData.abstract}
            onChange={handleChange}
            className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500"
            placeholder="Brief description of your project..."
          />
        </div>

        <div className="border-t pt-4 mt-4">
          <h3 className="text-lg font-semibold text-blue-600 mb-2">
            👨‍👩‍👧 Parent/Guardian Details
          </h3>
          <p className="text-sm text-gray-500 mb-3">
            We'll send registration confirmation via WhatsApp
          </p>

          <div>
            <label className="block text-sm font-medium text-gray-700">Parent/Guardian Name</label>
            <input
              type="text"
              name="parent_name"
              value={formData.parent_name}
              onChange={handleChange}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500"
              required
            />
          </div>

          <div className="mt-3">
            <label className="block text-sm font-medium text-gray-700">WhatsApp Number</label>
            <div className="mt-1 flex">
              <span className="inline-flex items-center px-3 rounded-l-md border border-r-0 border-gray-300 bg-gray-50 text-gray-500">
                +91
              </span>
              <input
                type="tel"
                name="parent_phone"
                placeholder="9876543210"
                value={formData.parent_phone}
                onChange={handleChange}
                className="flex-1 block w-full rounded-r-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500"
                required
              />
            </div>
            <p className="text-xs text-gray-500 mt-1">Enter 10-digit WhatsApp number</p>
          </div>

          <div className="mt-3">
            <label className="block text-sm font-medium text-gray-700">Email (Optional)</label>
            <input
              type="email"
              name="parent_email"
              value={formData.parent_email}
              onChange={handleChange}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500"
              placeholder="parent@email.com"
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={loading}
          className={`w-full py-3 px-4 border border-transparent rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 ${
            loading ? 'opacity-50 cursor-not-allowed' : ''
          }`}
        >
          {loading ? (
            <span className="flex items-center justify-center">
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Registering...
            </span>
          ) : (
            'Register & Send WhatsApp'
          )}
        </button>
      </form>
    </div>
  );
};

export default Register;
